import React from 'react';

/**
 * CTA component - Call-to-action section with title, subtitle and button
 * @param {Object} props - Component props
 * @param {string} props.title - CTA title
 * @param {string} props.subtitle - CTA subtitle
 * @param {string} props.buttonText - Button text
 * @param {Function} props.onButtonClick - Callback for button click
 */
const CTA = ({ 
  title = "Ready to manage your leave?",
  subtitle = "Join thousands of employees who track their leave efficiently",
  buttonText = "Get Started Now",
  onButtonClick
}) => {
  return (
    <div className="bg-gray-50 py-16">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center">
          <h3 className="text-2xl font-bold text-gray-900 mb-4">
            {title}
          </h3>
          <p className="text-lg text-gray-600 mb-8">
            {subtitle}
          </p>
          <button 
            onClick={onButtonClick}
            className="inline-flex items-center px-8 py-4 bg-blue-600 text-white rounded-full font-semibold text-lg hover:bg-blue-700 transition-colors shadow-lg hover:shadow-xl"
          >
            {buttonText}
          </button>
        </div>
      </div>
    </div>
  );
};

export default CTA;
